const e=JSON.parse('{"key":"v-f8a1b55c","path":"/posts/%E4%BB%A3%E7%A0%81%E9%A3%8E%E6%A0%BC/%E4%BB%A3%E7%A0%81%E9%A3%8E%E6%A0%BC%E7%9A%84%E7%90%86%E8%A7%A3.html","title":"代码风格的理解","lang":"en-US","frontmatter":{"icon":"pen-to-square","date":"2023-07-20T00:00:00.000Z","category":["代码风格"],"tag":["代码风格"],"star":true,"description":"代码风格的理解 个人感觉写代码本身这件事就是类似于构建房子，代码的功能实现就是房子的可居住能力，不同的代码实现都可以实现可居住的功能，但是居住功能不是房子的首要属性吗？不同的代码对应着不同功能的房子，打个比方：前端代码对应着商业楼，python对应着住宅楼，java代码代表着工业园。不同的代码风格可能代表着不同的建筑风格，很差的代码风格对应着木板房，好的代码可能就是高大的 CBD大楼。 第一步：打地基——代码模块设计 建造房子的第一步是打地基，地基也就代表着房子的实现的高度和建筑面积。同样代码的模块设计也就代表着代码的实现功能，以及实现功能的复杂度和可维护度。","head":[["meta",{"property":"og:url","content":"https://y-aong.github.io/orderlines_blog/orderlines_blog/posts/%E4%BB%A3%E7%A0%81%E9%A3%8E%E6%A0%BC/%E4%BB%A3%E7%A0%81%E9%A3%8E%E6%A0%BC%E7%9A%84%E7%90%86%E8%A7%A3.html"}],["meta",{"property":"og:site_name","content":"ORDERLINES"}],["meta",{"property":"og:title","content":"代码风格的理解"}],["meta",{"property":"og:description","content":"代码风格的理解 个人感觉写代码本身这件事就是类似于构建房子，代码的功能实现就是房子的可居住能力，不同的代码实现都可以实现可居住的功能，但是居住功能不是房子的首要属性吗？不同的代码对应着不同功能的房子，打个比方：前端代码对应着商业楼，python对应着住宅楼，java代码代表着工业园。不同的代码风格可能代表着不同的建筑风格，很差的代码风格对应着木板房，好的代码可能就是高大的 CBD大楼。 第一步：打地基——代码模块设计 建造房子的第一步是打地基，地基也就代表着房子的实现的高度和建筑面积。同样代码的模块设计也就代表着代码的实现功能，以及实现功能的复杂度和可维护度。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"og:updated_time","content":"2023-07-20T13:33:21.000Z"}],["meta",{"property":"article:author","content":"Y-aong"}],["meta",{"property":"article:tag","content":"代码风格"}],["meta",{"property":"article:published_time","content":"2023-07-20T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-07-20T13:33:21.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"代码风格的理解\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2023-07-20T00:00:00.000Z\\",\\"dateModified\\":\\"2023-07-20T13:33:21.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Y-aong\\",\\"url\\":\\"https://github.com/Y-aong\\"}]}"]]},"headers":[{"level":2,"title":"第一步：打地基——代码模块设计","slug":"第一步-打地基——代码模块设计","link":"#第一步-打地基——代码模块设计","children":[]},{"level":2,"title":"第二步：建房子——类的构建","slug":"第二步-建房子——类的构建","link":"#第二步-建房子——类的构建","children":[]},{"level":2,"title":"第三步：装修——函数的编写","slug":"第三步-装修——函数的编写","link":"#第三步-装修——函数的编写","children":[]},{"level":2,"title":"第四步：验房——测试","slug":"第四步-验房——测试","link":"#第四步-验房——测试","children":[]},{"level":2,"title":"第五步：入住——devops自动化部署","slug":"第五步-入住——devops自动化部署","link":"#第五步-入住——devops自动化部署","children":[]}],"git":{"createdTime":1689860001000,"updatedTime":1689860001000,"contributors":[{"name":"Y-aong","email":"1627469727@qq.com","commits":1}]},"readingTime":{"minutes":3.45,"words":1034},"filePathRelative":"posts/代码风格/代码风格的理解.md","localizedDate":"July 20, 2023","excerpt":"<h1> 代码风格的理解</h1>\\n<p>个人感觉写代码本身这件事就是类似于构建房子，代码的功能实现就是房子的可居住能力，不同的代码实现都可以实现可居住的功能，但是居住功能不是房子的首要属性吗？不同的代码对应着不同功能的房子，打个比方：前端代码对应着商业楼，<code>python</code>对应着住宅楼，<code>java</code>代码代表着工业园。不同的代码风格可能代表着不同的建筑风格，很差的代码风格对应着木板房，好的代码可能就是高大的 <code>CBD</code>大楼。</p>\\n<h2> 第一步：打地基——代码模块设计</h2>\\n<p><strong>建造房子的第一步是打地基，地基也就代表着房子的实现的高度和建筑面积。同样代码的模块设计也就代表着代码的实现功能，以及实现功能的复杂度和可维护度。</strong></p>","autoDesc":true}');export{e as data};
